var e=JSON.parse(`[{"id":"L3_1","type":"dialog","speaker":"POOR_ROOT_NPC_NULL","text":{"KOREA":"헉 헉…","JPN":"はあ、はあ……","ENG":"*Huff* *Huff*","TWN":"呼…咳咳…"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L4_1","type":"dialog","speaker":"POOR_ROOT_NPC_NULL","text":{"KOREA":"더는… 못 버티겠어…","JPN":"もう……これ以上は無理……","ENG":"I can't... go on anymore...","TWN":"我已經…撐不住了…"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L6_1","type":"dialog","speaker":"POOR_ROOT_NPC_NULL","text":{"KOREA":"나 이렇게… 죽는 거야…?","JPN":"こんなふうに……私は死んでしまうの……？","ENG":"Is this... how I'll die...?","TWN":"我就要這樣…死了嗎…？"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L16_1","type":"dialog","speaker":"MORS_SHADOW_CA_QM","text":{"KOREA":"괜찮은가. 소녀여.","JPN":"大丈夫か、少女よ。","ENG":"Are you all right, girl?","TWN":"…你沒事吧，孩子。"},"stage":{"bg":"SKY_SUNSET","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L17_1","type":"dialog","speaker":"POOR_ROOT_NPC_NULL","text":{"KOREA":"당신은…?","JPN":"あなたは……？","ENG":"You are...?","TWN":"你是…？"},"stage":{"bg":"SKY_SUNSET","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L18_1","type":"dialog","speaker":"MORS_SHADOW_CA_QM","text":{"KOREA":"난민들을 마물로부터 홀로 지켰다고 들었다.","JPN":"難民たちを魔物からたった一人で守ったくれたと聞いた。","ENG":"I heard that you had protected the refugees from the monsters all by yourself.","TWN":"聽說你獨自從怪物爪下守護了那些難民。"},"stage":{"bg":"SKY_SUNSET","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L19_1","type":"dialog","speaker":"MORS_SHADOW_CA_QM","text":{"KOREA":"아직 어린 나이에도 용감하구나.","JPN":"まだ幼い子どもなのに、勇敢であるな。","ENG":"For someone as young as you, I admire your courage.","TWN":"小小年紀卻如此勇敢。"},"stage":{"bg":"SKY_SUNSET","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L20_1","type":"dialog","speaker":"POOR_ROOT_NPC_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"SKY_SUNSET","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L21_1","type":"dialog","speaker":"POOR_ROOT_NPC_NULL","text":{"KOREA":"전 최선을 다했다고 생각했는데…","JPN":"私は力の限りを尽くしたけど……","ENG":"I thought I was just doing my best...","TWN":"我覺得我已經盡力了…"},"stage":{"bg":"SKY_SUNSET","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L22_1","type":"dialog","speaker":"POOR_ROOT_NPC_NULL","text":{"KOREA":"아이를 지키려던 엄마가… 마물에게 죽었어요.","JPN":"子どもを庇おうとした母親が……魔物に殺されました。","ENG":"But the monsters... got the mother who was protecting her child.","TWN":"那個想要保護孩子的母親…被怪物殺死了。"},"stage":{"bg":"SKY_SUNSET","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L24_1","type":"dialog","speaker":"POOR_ROOT_NPC_NULL","text":{"KOREA":"제가 좀 더 강한 사람이었으면, 그 사람을 구할 수 있었겠죠.","JPN":"私がもっと強かったら、あの母親も助けることができたんでしょう。","ENG":"If only I was a bit stronger, I could've saved her too.","TWN":"如果我再強一點，或許能救下她…"},"stage":{"bg":"SKY_SUNSET","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L25_1","type":"dialog","speaker":"MORS_SHADOW_CA_QM","text":{"KOREA":"자책하지 말아라.","JPN":"自分を責めるな。","ENG":"Do not blame yourself.","TWN":"不要自責。"},"stage":{"bg":"SKY_SUNSET","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L26_1","type":"dialog","speaker":"MORS_SHADOW_CA_QM","text":{"KOREA":"네가 나서지 않았다면 수많은 난민들이 희생되었을 것이다.","JPN":"そなたがいてくれなかったら、多くの難民が犠牲になっていたところだ。","ENG":"If you had not stepped forward, many refugees would have lost their lives.","TWN":"如果不是你挺身而出，會有更多難民死去。"},"stage":{"bg":"SKY_SUNSET","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L28_1","type":"dialog","speaker":"MORS_SHADOW_CA_NULL","text":{"KOREA":"나의 이름은 에클레시아.","JPN":"我の名はエクレシア。","ENG":"My name is Ecclesia.","TWN":"我的名字艾可露西亞。"},"stage":{"bg":"SKY_SUNSET","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_CA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"MORS_SHADOW_CA_NULL","text":{"KOREA":"네 이름은 무엇이냐?","JPN":"そなたの名は？","ENG":"What is yours?","TWN":"你叫什麼名字？"},"stage":{"bg":"SKY_SUNSET","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_CA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"POOR_ROOT_NPC_NULL","text":{"KOREA":"이름은…  없어요.","JPN":"名前は、ありません。","ENG":"I don't... have a name.","TWN":"我沒有…名字。"},"stage":{"bg":"SKY_SUNSET","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_CA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"POOR_ROOT_NPC_NULL","text":{"KOREA":"저는 이름을 가지면 안 된다고 그랬거든요.","JPN":"私は名前を持ってはいけないそうです。","ENG":"I was told that I shouldn't be given one.","TWN":"他們說我不能有名字。"},"stage":{"bg":"SKY_SUNSET","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_CA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"MORS_SHADOW_CA_NULL","text":{"KOREA":"가족은 어디에 있지? 돌아갈 곳은 있느냐?","JPN":"家族はどこにいる？　帰る場所はあるのか？","ENG":"Where is your family? Do you have a place to return to?","TWN":"你的家人在哪裡？有地方可以回去嗎？"},"stage":{"bg":"SKY_SUNSET","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_CA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"POOR_ROOT_NPC_NULL","text":{"KOREA":"없어요.","JPN":"いいえ。","ENG":"No.","TWN":"沒有了。"},"stage":{"bg":"SKY_SUNSET","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_CA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"POOR_ROOT_NPC_NULL","text":{"KOREA":"어머니랑 둘이서 살았는데, 얼마 전에 역병으로 돌아가셨어요.","JPN":"お母さんと二人で暮らしていたんですが、少し前に疫病に罹り亡くなりました。","ENG":"I used to live with my mom, but she died from the plague recently.","TWN":"我和媽媽一起生活，但她前不久因為瘟疫去世了。"},"stage":{"bg":"SKY_SUNSET","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_CA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"POOR_ROOT_NPC_NULL","text":{"KOREA":"역병 환자가 있던 집은 남겨두면 안 된다면서… 어른들이 다 불태웠고요.","JPN":"疫病患者の家は残しておけないと……大人たちに家は燃やされてしまいました。","ENG":"And the adults... burned down my house, saying that they can't let a house of a plague patient remain.","TWN":"大人說不能留下有瘟疫患者的房子…所以全都燒了。"},"stage":{"bg":"SKY_SUNSET","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_CA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"MORS_SHADOW_CA_NULL","text":{"KOREA":"…그런가.","JPN":"……そうであったか。","ENG":"…I see.","TWN":"是嗎…？"},"stage":{"bg":"SKY_SUNSET","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_CA_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"MORS_SHADOW_CA_NULL","text":{"KOREA":"내가 너에게 머물 곳을 마련해주마.","JPN":"我がそなたに住む場所を与えよう。","ENG":"Then I shall put a roof over your head.","TWN":"我會為你安排一個住處。"},"stage":{"bg":"SKY_SUNSET","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_CA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"MORS_SHADOW_CA_NULL","text":{"KOREA":"대신, 하나 제안을 하고 싶구나.","JPN":"その代わり一つ提案させてほしい。","ENG":"In return, I would like to propose an offer.","TWN":"不過，我想再提一個提議。"},"stage":{"bg":"SKY_SUNSET","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_CA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"POOR_ROOT_NPC_NULL","text":{"KOREA":"제안…?","JPN":"提案……ですか？","ENG":"An offer...?","TWN":"提議…？"},"stage":{"bg":"SKY_SUNSET","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MORS_SHADOW_CA_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"POOR_ROOT_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L44_1","type":"dialog","speaker":"MORS_SHADOW_CA_NULL","text":{"KOREA":"팔라딘이 되어, 우리 순례단과 함께하거라.","JPN":"パラディンとなり、巡礼団に加わることだ。","ENG":"Become a paladin and join the pilgrimage.","TWN":"成為聖騎士，加入我們的朝聖團吧。"},"stage":{"bg":"SKY_SUNSET","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MORS_SHADOW_CA_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"POOR_ROOT_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L45_1","type":"dialog","speaker":"MORS_SHADOW_CA_NULL","text":{"KOREA":"훈련을 통해 강해진다면, 오늘보다 더 많은 사람을 지킬 수 있게 될 테니.","JPN":"訓練を受け強くなれば、今よりさらに多くの人を守ることができるようになるであろう。","ENG":"If you become stronger through training, you will be able to protect more people.","TWN":"透過訓練，你還可以變得更強，你將能夠保護更多的人。"},"stage":{"bg":"SKY_SUNSET","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MORS_SHADOW_CA_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"POOR_ROOT_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L46_1","type":"dialog","speaker":"POOR_ROOT_NPC_NULL","text":{"KOREA":"에클레시아님 같은… 팔라딘이요?","JPN":"エクレシア様と同じ……パラディンに？","ENG":"A paladin... like you, Miss Ecclesia?","TWN":"像艾克蕾西亞那樣的…聖騎士嗎？"},"stage":{"bg":"SKY_SUNSET","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MORS_SHADOW_CA_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"POOR_ROOT_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L47_1","type":"dialog","speaker":"POOR_ROOT_NPC_NULL","text":{"KOREA":"그런 건 감히 꿈도 못 꿔봤어요.","JPN":"そんなこと、夢にも思っていませんでした。","ENG":"I've never dared to even dream about becoming one before.","TWN":"那可是我連想都不敢想的事。"},"stage":{"bg":"SKY_SUNSET","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MORS_SHADOW_CA_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"POOR_ROOT_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L48_1","type":"dialog","speaker":"POOR_ROOT_NPC_NULL","text":{"KOREA":"제가… 할 수 있을까요? 팔라딘은 세례를 받은 고결한 사람만 될 수 있다고 들었는데.","JPN":"私に……できるんでしょうか？　パラディンは洗礼を受けた高潔な者でないとなれないはずですが。","ENG":"Do you think... I can do it? I heard that only noble people who have been baptized can become paladins.","TWN":"我…可以嗎？我聽說只有接受洗禮的高貴之人才能成為聖騎士。"},"stage":{"bg":"SKY_SUNSET","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MORS_SHADOW_CA_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"POOR_ROOT_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L49_1","type":"dialog","speaker":"MORS_SHADOW_CA_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"SKY_SUNSET","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MORS_SHADOW_CA_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"POOR_ROOT_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L50_1","type":"dialog","speaker":"MORS_SHADOW_CA_NULL","text":{"KOREA":"걱정 말아라. 너의 마음에서 본 것은 틀림없는 고결함이니.","JPN":"心配には及ばない。そなたの心のには紛れもない高潔さが宿っている。","ENG":"Do not worry. What I see in your heart is unmistakable nobility.","TWN":"別擔心，我在你的心中看到了無可置疑的高貴。"},"stage":{"bg":"SKY_SUNSET","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MORS_SHADOW_CA_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"POOR_ROOT_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L1_1","type":"dialog","speaker":"MORS_SHADOW_CA_NULL","text":{"KOREA":"내가 너에게 이름을 주고, 성자로서 살아가는 법을 가르쳐주마.","JPN":"我がそなたに名前を与え、聖者として生きていく方法を教えてやろう。","ENG":"I shall bestow you a name, and teach you the way of a Helgon.","TWN":"我會賜你一個名字，並教你作為聖者的生活方式。"},"stage":{"bg":"SKY_SUNSET","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MORS_SHADOW_CA_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"POOR_ROOT_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L2_1","type":"dialog","speaker":"POOR_ROOT_NPC_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"SKY_SUNSET","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MORS_SHADOW_CA_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"POOR_ROOT_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L3_1","type":"dialog","speaker":"POOR_ROOT_NPC_NULL","text":{"KOREA":"저도 갖고 싶어요. 이름.","JPN":"私も名前がほしいです。","ENG":"I want it too. A name, that is.","TWN":"名字…我想要一個名字。"},"stage":{"bg":"SKY_SUNSET","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MORS_SHADOW_CA_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"POOR_ROOT_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L5_1","type":"dialog","speaker":"MORS_SHADOW_CA_NULL","text":{"KOREA":"…네 이름은 모드레드.","JPN":"……そなたの名前はモードレッド。","ENG":"...Your name shall be Mordred.","TWN":"…你的名字是莫德雷德。"},"stage":{"bg":"SKY_SUNSET","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_CA_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"MORS_SHADOW_CA_NULL","text":{"KOREA":"아발론의 언어로, 더없이 용맹한 사람이란 뜻이다.","JPN":"アバロンの言葉で、この上ない勇猛な者という意味だ。","ENG":"It means, \\"the utmost courageous one\\" in Avalonian.","TWN":"照阿瓦隆語的語意，是無比勇敢的人。"},"stage":{"bg":"SKY_SUNSET","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_CA_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"MORS_SHADOW_CA_NULL","text":{"KOREA":"오늘, 태양문의 빛이 타기리온의 탑을 발견했다고 하더구나.","JPN":"本日、太陽の門の光がタギリオンの塔を見つけたそうだ。","ENG":"Today, the Solar Gate's light has discovered Thagirion's Tower.","TWN":"今天，太陽門的光芒照耀到塔基里翁的塔。"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_CA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"MORDRED_ROOT_NULL_NULL","text":{"KOREA":"잘 됐네요. 곧 마왕을 처단할 수 있는 거군요.","JPN":"それはなによりです。まもなく魔王の討伐ができるのですね？","ENG":"Good news. We will soon rid the Demon Lord from this world.","TWN":"太好了，很快就能討伐魔王了。"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORDRED_ROOT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"MORS_SHADOW_CA_NULL","text":{"KOREA":"그래, 머지않아 성전을 치르게 될 것이다.","JPN":"ああ、やがて聖戦が行われるだろう。","ENG":"Yes. The holy war will soon commence.","TWN":"是的，不久之後我們將進行一場聖戰。"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MORS_SHADOW_CA_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"MORDRED_ROOT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L15_1","type":"dialog","speaker":"MORS_SHADOW_CA_NULL","text":{"KOREA":"그날이 왔을 땐, 너도 생도가 아닌 순례단의 자랑스러운 일원이 되어있겠지.","JPN":"その時が来たら、そなたも候補生としてではなく、巡礼団の誇り高き一員となっていることだろう。","ENG":"When that day comes, you will also be a proud member of the pilgrimage and not a cadet.","TWN":"那一天到來時，你也將不再是實習生，而是朝聖團的驕傲成員。"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MORS_SHADOW_CA_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"MORDRED_ROOT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L16_1","type":"dialog","speaker":"MORDRED_ROOT_NULL_NULL","text":{"KOREA":"마왕을 쓰러트리고 나면 역병이 사라지고 평화가 찾아오는 거겠죠?","JPN":"魔王を倒せば、疫病はこの世からなくなり、平和が訪れるのですね？","ENG":"Peace will return and the plague will be no more once the Demon Lord is defeated, right?","TWN":"打倒魔王後，瘟疫會消失，和平會到來吧？"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MORS_SHADOW_CA_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"MORDRED_ROOT_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L17_1","type":"dialog","speaker":"MORS_SHADOW_CA_NULL","text":{"KOREA":"당도한 적 없는 미래를 확신할 순 없다, 모드레드.","JPN":"たどり着いたことのない未来について断言はできない、モードレッドよ。","ENG":"There is no certainty in the future, Mordred.","TWN":"未曾發生的將來是無法確定的，莫德雷德。"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MORS_SHADOW_CA_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MORDRED_ROOT_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L18_1","type":"dialog","speaker":"MORS_SHADOW_CA_NULL","text":{"KOREA":"하지만 이 길이 우리가 선택한 길이니, 망설임도 필요 없으리라.","JPN":"だが、これが我々が見出した活路だ。迷う理由はなかろう。","ENG":"However, this is the path we have chosen. There is no room for hesitation.","TWN":"但這是我們選擇的道路，不需要猶豫。"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MORS_SHADOW_CA_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"MORDRED_ROOT_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L19_1","type":"dialog","speaker":"MORDRED_ROOT_NULL_NULL","text":{"KOREA":"망설이지 않아요.","JPN":"迷いはありません。","ENG":"I won't hesitate.","TWN":"我不會再猶豫了。"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MORS_SHADOW_CA_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"MORDRED_ROOT_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L21_1","type":"dialog","speaker":"MORDRED_ROOT_NULL_NULL","text":{"KOREA":"당신의 빛을 좇아 여기까지 왔으니까요.","JPN":"私はあなたの光を追いかけてここまで来たんです。","ENG":"Because I followed your light here.","TWN":"因為我是追隨你的光芒來到這裡的。"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORDRED_ROOT_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L24_1","type":"narration","speaker":null,"text":{"KOREA":"믿음이 있었다.","JPN":"信仰があった。","ENG":"I had faith.","TWN":"我有信仰。"},"stage":{"bg":"NOMAD_BORDER","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L25_1","type":"narration","speaker":null,"text":{"KOREA":"빛을 따라 앞으로 나아가면 된다는 믿음.","JPN":"光に従って、前へ進めばよいという信仰。","ENG":"Faith that I could move forward by following the light.","TWN":"我相信只要追隨著光芒前進就行。"},"stage":{"bg":"NOMAD_BORDER","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L28_1","type":"narration","speaker":null,"text":{"KOREA":"순례단이 되어 마왕을 토벌하는 것만이 나에게 주어진 의무라고 생각했다.","JPN":"巡礼団となり、魔王を討伐することだけが私に与えられた使命だと考えていた。","ENG":"I thought that it was my sole duty to become a member of the pilgrimage and defeat the Demon Lord.","TWN":"我認為加入朝聖團討伐魔王是我唯一的職責。"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L29_1","type":"narration","speaker":null,"text":{"KOREA":"하지만 내 운명은 그것을 쉽게 허락하지 않았다.","JPN":"でも、私が背負う運命は、それを簡単に許してはくれなかった。","ENG":"But my fate wouldn't allow it so easily.","TWN":"但我的命運並未輕易允許這一切。"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L31_1","type":"dialog","speaker":"CLARIC_ROOT_NPC_NULL","text":{"KOREA":"순례단의 견습 팔라딘, 모드레드.","JPN":"巡礼団の見習いパラディン、モードレッド。","ENG":"Apprentice Paladin of the pilgrimage, Mordred.","TWN":"朝聖團的實習聖騎士，莫德雷德。"},"stage":{"bg":"PRISON_NIGHT_02","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORDRED_ROOT_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"CLARIC_ROOT_NPC_NULL","text":{"KOREA":"태양문의 위병식을 앞두고 당신을 심문대 앞에서 보게 될 줄은 몰랐군요.","JPN":"太陽の門の出征式の前にして、あなたと尋問台で会うことになるとは思いませんでしたよ。","ENG":"I did not expect to see you at the inquisition stand right before the Solar Gate's guard ceremony.","TWN":"沒想到在太陽門的守衛交接儀式前會先在審問台見到你。"},"stage":{"bg":"PRISON_NIGHT_02","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORDRED_ROOT_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"MORDRED_ROOT_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"…"},"stage":{"bg":"PRISON_NIGHT_02","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORDRED_ROOT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"CLARIC_ROOT_NPC_NULL","text":{"KOREA":"아직 늦지 않았습니다. 당신에게 마지막으로 죄를 뉘우칠 기회를 드리죠.","JPN":"まだ間に合います。あなたには自分の罪を悔いるチャンスを与えましょう。","ENG":"It's not too late. I will give you one last chance to repent for your sins.","TWN":"還不算太晚。我給你最後一次懺悔的機會。"},"stage":{"bg":"PRISON_NIGHT_02","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORDRED_ROOT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"MORDRED_ROOT_NULL_NULL","text":{"KOREA":"전… 죄를 짓지 않았어요.","JPN":"私は……罪を犯してなどいません。","ENG":"I... haven't committed a sin.","TWN":"我…沒有犯罪。"},"stage":{"bg":"PRISON_NIGHT_02","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORDRED_ROOT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"INQUI_ROOT_NPC_NULL","text":{"KOREA":"그대는 이교도를 심판하는 심문관을 위협했다!","JPN":"汝は異教徒を裁く立場である尋問官を威嚇したんだぞ！","ENG":"You threatened the inquisitor who puts pagans on trial!","TWN":"你威脅了審判異教徒的審問官！"},"stage":{"bg":"PRISON_NIGHT_02","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORDRED_ROOT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"MORDRED_ROOT_NULL_NULL","text":{"KOREA":"그 사람들은 저항도 못하는 아이에게 칼을 휘둘렀어요!","JPN":"あの人は無抵抗な子どもに、剣を突き刺したんです！","ENG":"Those people swung their swords at a child who couldn't even resist!","TWN":"那些人在對毫無反抗之力的孩子揮刀！"},"stage":{"bg":"PRISON_NIGHT_02","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORDRED_ROOT_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L40_1","type":"dialog","speaker":"MORDRED_ROOT_NULL_NULL","text":{"KOREA":"이교도이기 전에 같은 사람이잖아요! 피를 흘리기 전에, 공정한 재판을 받았어야 한다고요!","JPN":"異教徒である前に、同じ人間です！　血を流させる前に、まずは公正な裁判を受けさせるべきだったんです！","ENG":"Pagans are still people! Before they spilled blood, they needed to be put on a fair trial!","TWN":"在成為異教徒之前，他們也是人！在流血之前，他們應該接受公正的審判！"},"stage":{"bg":"PRISON_NIGHT_02","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORDRED_ROOT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"CLARIC_ROOT_NPC_NULL","text":{"KOREA":"교단을 섬기는 팔라딘의 입에서 이교도를 감싸는 발언이 나오다니.","JPN":"教団に仕える身であるパラディンが、異教徒の肩を持つような発言を口にするとは。","ENG":"How dare a paladin who serves the Order speak of protecting pagans.","TWN":"從侍奉教團的聖騎士口中，竟然說出為異教徒辯護的話。"},"stage":{"bg":"PRISON_NIGHT_02","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORDRED_ROOT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"CLARIC_ROOT_NPC_NULL","text":{"KOREA":"정말로 유감이군요. 모드레드.","JPN":"誠に遺憾です。モードレッド。","ENG":"I am truly sorry, Mordred.","TWN":"真是遺憾，莫德雷德。"},"stage":{"bg":"PRISON_NIGHT_02","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORDRED_ROOT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L46_1","type":"narration","speaker":null,"text":{"KOREA":"하루는 난민촌의 아이가 심문관들에게 붙잡히는 걸 보았다.","JPN":"その日は、難民村の子どもが尋問官に掴まる光景を目にした。","ENG":"One day, I saw a child from the refugee camp being captured by the inquisitors.","TWN":"那天，我看到難民營的孩子被審問官帶走。"},"stage":{"bg":"CAMP","bgm":"CUTSCENE_TALK_04","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L47_1","type":"narration","speaker":null,"text":{"KOREA":"불경한 예언을 믿는 이교도라는 게 그 이유였다.","JPN":"不敬な予言を信奉する異教徒であるということが理由であった。","ENG":"The reason was that the child was a pagan who believed in blasphemous prophecies.","TWN":"罪名是褻瀆的預言。"},"stage":{"bg":"CAMP","bgm":"CUTSCENE_TALK_04","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L48_1","type":"narration","speaker":null,"text":{"KOREA":"심문관 중 한 명이 칼을 뽑아 들었고, 나를 본 그 아이는 내 이름을 외쳤다.","JPN":"尋問官の一人が剣を抜き、私を見た子どもは私の名前を叫んだ。","ENG":"During the interrogation, they drew their swords at the child. Seeing me there, the child shouted my name.","TWN":"在審問中，其中一個審問官對著孩子拔出劍。"},"stage":{"bg":"CAMP","bgm":"CUTSCENE_TALK_04","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L49_1","type":"narration","speaker":null,"text":{"KOREA":"사사로이 나서지 말라던 충고가 떠올랐지만…","JPN":"いちいち構うなという忠告が頭をよぎったけど……","ENG":"Although I was advised to not take personal action...","TWN":"雖然我想起不要私自行動的忠告，但那個孩子看著我，喊出我的名字…"},"stage":{"bg":"CAMP","bgm":"CUTSCENE_TALK_04","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L50_1","type":"narration","speaker":null,"text":{"KOREA":"나는 차마 두고 볼 수 없었다.","JPN":"私はどうしても見て見ぬふりをすることができなかった。","ENG":"I couldn't bear to neglect what was going on.","TWN":"心中的那個聲音無法讓我再無動於衷…"},"stage":{"bg":"CAMP","bgm":"CUTSCENE_TALK_04","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L3_1","type":"narration","speaker":null,"text":{"KOREA":"이교도를 도왔다는 이유로 난 심문을 받게 됐고…","JPN":"異教徒の味方をしたという罪状で尋問を受けることとなり……","ENG":"I was questioned for aiding a pagan, and...","TWN":"因為幫助異教徒，我被審問…"},"stage":{"bg":"PRISON_NIGHT_02","bgm":"CUTSCENE_TALK_04","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L4_1","type":"narration","speaker":null,"text":{"KOREA":"지금껏 숨겨왔던 몸의 낙인을 들키는 건… 시간문제였다.","JPN":"ずっと隠してきた烙印が見つかってしまうのは……時間の問題となった。","ENG":"it was only a matter of time... before the hidden mark on my body would be revealed.","TWN":"一直隱藏的烙印被發現也只是時間問題。"},"stage":{"bg":"PRISON_NIGHT_02","bgm":"CUTSCENE_TALK_04","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L7_1","type":"dialog","speaker":"INQUI_ROOT_NPC_NULL","text":{"KOREA":"반역자의 낙인은 아발론의 왕 시해자 가문에게 내려진 죄의 표식이다.","JPN":"反逆者の烙印はアバロンの王を殺害した一族に与えられた罪の印である。","ENG":"The brand of the traitor is a mark of sin passed down the king-slayer family of Avalon.","TWN":"叛徒烙印是刺殺阿瓦隆王的家族印記。"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L8_1","type":"dialog","speaker":"INQUI_ROOT_NPC_NULL","text":{"KOREA":"그 핏줄을 타고난 후손은 모두 가슴에 낙인을 품은 채 태어나지.","JPN":"その血を受け継いだ子孫は、胸に烙印を持ったまま生まれる。","ENG":"The bloodline's descendants were all born with the brand on their chest.","TWN":"那些血脈的後代，胸口都帶著烙印出生。"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L9_1","type":"dialog","speaker":"INQUI_ROOT_NPC_NULL","text":{"KOREA":"그 낙인을 가진 죄인이 고결한 팔라딘을 꿈꾸다니, 참으로 가증스럽구나.","JPN":"あの烙印を持つ罪人が高潔なパラディンを夢見るなど、なんと傲慢な。","ENG":"How dare a sinner carrying that mark ever dream of becoming a noble paladin. Disgusting.","TWN":"身上有烙印的罪人竟然也敢夢想成為高貴的聖騎士，真是可笑。"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L10_1","type":"dialog","speaker":"MORDRED_ROOT_NULL_NULL","text":{"KOREA":"전… 죄인이 아니에요.","JPN":"私は……罪など犯していません。","ENG":"I'm... not a sinner.","TWN":"我…不是罪人。"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORDRED_ROOT_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"INQUI_ROOT_NPC_NULL","text":{"KOREA":"반역자의 낙인이 곧 죄악이고! 그것을 숨긴 것은 더더욱 큰 중죄다!","JPN":"反逆者の烙印はそれ自体が罪悪である！　それを隠していたのはさらなる重罪だ！","ENG":"Having the mark of the traitor itself is your sin! And an even greater sin to have hidden it!","TWN":"叛徒的烙印就是罪！隱瞞更是大罪！"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORDRED_ROOT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"INQUI_ROOT_NPC_NULL","text":{"KOREA":"그런 중죄인이 이교도를 감싼 것에 대해선 더 논할 가치도 없다!","JPN":"そのような重罪人が、異教徒の肩を持ったとなれば、これ以上の裁判は無意味である！","ENG":"I am wasting my breath discussing this sinner's actions of protecting a pagan!","TWN":"和這比起來，包庇異教徒的行為根本不值一提！"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORDRED_ROOT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"MORDRED_ROOT_NULL_NULL","text":{"KOREA":"재판도 없이 사람을 해치는 건 어긋난 일이잖아요!","JPN":"裁判なしで人の命を奪うのは、法律に反することです！","ENG":"But it's wrong to punish someone without a trial!","TWN":"不經過審判就傷害人是不對的！"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORDRED_ROOT_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"MORDRED_ROOT_NULL_NULL","text":{"KOREA":"이교도니, 낙인이니, 그까짓 게 무슨 상관인 거죠?","JPN":"異教徒だの、烙印だの、私にはなんの関係もありません！","ENG":"What does being a pagan or having the mark have anything to do with that?","TWN":"什麼異教徒，什麼烙印，那些有什麼關係？"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORDRED_ROOT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"CITIZEN_ROOT_NPC_NULL","text":{"KOREA":"들었어요? 여기까지 와서도 이교도의 편을 들다니, 역시 피는 속일 수가 없네요.","JPN":"聞きましたか？　この期に及んでも、異教徒の味方をするなんて、やっぱり血は争えないということですな。","ENG":"Did you hear? She's still taking the pagan's side. Guess it's in her blood.","TWN":"聽到沒？竟然還站在異教徒那邊，果然血脈裡的罪是無法騙人的。"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORDRED_ROOT_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"MORDRED_ROOT_NULL_NULL","text":{"KOREA":"이 재판은 잘못됐어요! 에클레시아 추기경님을 불러주세요! 전 결백하다고요!","JPN":"この裁判は間違っている！　エクレシア枢機卿を呼んできてください！　私は潔白だ！","ENG":"This trial is wrong! Call Her Eminence! I'm innocent!","TWN":"這個審判是錯的！請找艾克蕾西亞主教來！我是無辜的！"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORDRED_ROOT_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L21_1","type":"dialog","speaker":"INQUI_ROOT_NPC_NULL","text":{"KOREA":"이런 순간에 그분의 명성을 이용하려 들다니. 배은망덕하군.","JPN":"この場で、あの方の名を利用しようとするなんて、無礼にもほどがある。","ENG":"Trying to use Her Eminence's reputation even now. How ungrateful of you.","TWN":"在這種時候還想利用她的名聲，真是忘恩負義的東西。"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORDRED_ROOT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"INQUI_ROOT_NPC_NULL","text":{"KOREA":"너를 믿고 순례단의 자리를 내어준 그분은 지금 이단재판에 회부되었음을 모르는 거냐!","JPN":"お前を信用して、巡礼団の一員にしたあのお方は、今異端裁判にかけられているんだぞ！","ENG":"Have you no clue that Her Eminence, the one who trusted you and gave you a seat in the pilgrimage, has been brought to trial of heresy?!","TWN":"你不知道嗎？就因為她信任你，還讓你加入朝聖團，所以她現在已經受到異端裁判庭的調查！"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORDRED_ROOT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"MORDRED_ROOT_NULL_NULL","text":{"KOREA":"저 때문에… 추기경님이…?","JPN":"枢機卿様が……私のせいで……？","ENG":"Because of me... Her Eminence is…?","TWN":"因為我…主教她…？"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORDRED_ROOT_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"INQUI_ROOT_NPC_NULL","text":{"KOREA":"신실한 그분의 믿음을 배반하고도 일말의 죄책감조차 느끼지 못하고 있구나.","JPN":"摯実なあの方の信頼を裏切ってもなお、背徳感など微塵も感じていないようだな。","ENG":"It seems that you do not feel the slightest of guilt for betraying Her Eminence's trust.","TWN":"你背叛了她那虔誠的信仰，竟然連一絲罪惡感都沒有。"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORDRED_ROOT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"INQUI_ROOT_NPC_NULL","text":{"KOREA":"진정으로 속죄를 바란다면, 너의 원죄를 부정하지마라! 반역자!","JPN":"心から反省し、罪を償いたいという気持ちがあるなら、自分の原罪を否定するな、反逆者よ！","ENG":"If you truly want redemption, do not deny your original sin, traitor!","TWN":"如果你真心想要贖罪，就不要否認你的罪！叛徒！"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORDRED_ROOT_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_COMBAT_MONSTER_HIT_SMALL"},{"id":"L29_1","type":"dialog","speaker":"MORDRED_ROOT_NULL_NULL","text":{"KOREA":"아니야… 난 반역자가 아니야…","JPN":"違う……私は反逆者じゃない……","ENG":"No...! I'm not a traitor...","TWN":"不是的…我不是叛徒…"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L31_1","type":"dialog","speaker":"CITIZEN_ROOT_NPC_NULL","text":{"KOREA":"더 큰 죄악을 저지르기 전에 심판대에 매달아요!","JPN":"さらなる悪事を働く前に、審判を受けさせましょう！","ENG":"Hang her on the scaffold before she commits even greater sins!","TWN":"在她犯下更大罪行之前，把她送上審判台！"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_CUTSCEN_CROWD_NOISE_04"},{"id":"L32_1","type":"dialog","speaker":"CITIZEN_ROOT_NPC_NULL","text":{"KOREA":"저 끔찍한 낙인을 태양의 불로 정화시켜야 합니다!","JPN":"あのおぞましい烙印を、太陽の炎をもって浄化しなければなりません！","ENG":"We must purify that horrible mark with the sun's fire!","TWN":"必須用太陽的火焰淨化那可怕的烙印！"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_CUTSCEN_CROWD_NOISE"},{"id":"L35_1","type":"dialog","speaker":"MORDRED_ROOT_NULL_NULL","text":{"KOREA":"난 그저 내 사명을 지키기 위해…","JPN":"私はただ、自分の使命を全うするために……","ENG":"I was just trying...","TWN":"我是在履行我的使命…"},"stage":{"bg":"PRISON_NIGHT_02","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L36_1","type":"dialog","speaker":"MORDRED_ROOT_NULL_NULL","text":{"KOREA":"노력했을 뿐인데…","JPN":"尽くしてきただけなのに……","ENG":"to uphold my duties...","TWN":"我只是為此努力而已…"},"stage":{"bg":"PRISON_NIGHT_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L38_1","type":"dialog","speaker":"MORS_SHADOW_CA_NULL","text":{"KOREA":"일어나거라, 모드레드.","JPN":"立ち上がるのだ、モードレッド。","ENG":"Get up, Mordred.","TWN":"起來吧，莫德雷德。"},"stage":{"bg":"PRISON_NIGHT_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"MORS_SHADOW_CA_NULL","face":"UNIT_IDLE"}}}},{"id":"L39_1","type":"dialog","speaker":"MORDRED_ROOT_NULL_NULL","text":{"KOREA":"추기경님…? 어째서 여기에…?","JPN":"枢機卿様……？　どうしてここに……？","ENG":"Her Eminence...? What are you doing here...?","TWN":"主教…？主教為什麼會在這裡…？"},"stage":{"bg":"PRISON_NIGHT_02","bgm":"CUTSCENE_TRAGEDY_SOFT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MORDRED_ROOT_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"MORS_SHADOW_CA_NULL","face":"UNIT_IDLE"}}}},{"id":"L41_1","type":"dialog","speaker":"MORS_SHADOW_CA_NULL","text":{"KOREA":"새벽이 밝으면, 교단은 너를 심판대에 세울 것이다.","JPN":"夜が明ければ、教団はそなたを断罪の台に乗せるだろう。","ENG":"When dawn breaks, the Order will bring you to justice.","TWN":"黎明之時，教團會把你送上審判台。"},"stage":{"bg":"PRISON_NIGHT_02","bgm":"CUTSCENE_TRAGEDY_SOFT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MORDRED_ROOT_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MORS_SHADOW_CA_NULL","face":"UNIT_IDLE"}}}},{"id":"L42_1","type":"dialog","speaker":"MORDRED_ROOT_NULL_NULL","text":{"KOREA":"그럼 전… 죽는 건가요?","JPN":"そしたら私は……死ぬんですか？","ENG":"Then... am I going to die?","TWN":"那我…會死嗎？"},"stage":{"bg":"PRISON_NIGHT_02","bgm":"CUTSCENE_TRAGEDY_SOFT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MORDRED_ROOT_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MORS_SHADOW_CA_NULL","face":"UNIT_IDLE"}}}},{"id":"L43_1","type":"dialog","speaker":"MORS_SHADOW_CA_NULL","text":{"KOREA":"두려움이 신앙의 깊이를 넘어서면, 사람은 이성을 잃고 말지.","JPN":"恐れの気持ちが信仰心を超えたとき、人は理性を失う。","ENG":"When fear exceeds the depths of faith, one loses rationality.","TWN":"當恐懼超越信仰時，人就會失去理智。"},"stage":{"bg":"PRISON_NIGHT_02","bgm":"CUTSCENE_TRAGEDY_SOFT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MORDRED_ROOT_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MORS_SHADOW_CA_NULL","face":"UNIT_IDLE"}}}},{"id":"L44_1","type":"dialog","speaker":"MORS_SHADOW_CA_NULL","text":{"KOREA":"저들이 두려워하는 것은 너의 죄가 아닌 반역자의 낙인이다.","JPN":"あの者どもが恐れているのは、そなたの罪ではなく、反逆者の烙印である。","ENG":"What they fear is the brand of the traitor, not your sin.","TWN":"他們害怕的不是你的罪，而是叛徒的烙印。"},"stage":{"bg":"PRISON_NIGHT_02","bgm":"CUTSCENE_TRAGEDY_SOFT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MORDRED_ROOT_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MORS_SHADOW_CA_NULL","face":"UNIT_IDLE"}}}},{"id":"L45_1","type":"dialog","speaker":"MORS_SHADOW_CA_NULL","text":{"KOREA":"그 낙인이 존재하는 한, 교단은 무슨 수를 써서라도 너를 없애려고 하겠지.","JPN":"その烙印が存在する限り、教団はどんな手を使ってでも、そなたを消そうとするはずだ。","ENG":"As long as that mark is on you, the Order will stop at no lengths to get rid of you.","TWN":"只要那個烙印存在，教團就會不擇手段地想要除掉你。"},"stage":{"bg":"PRISON_NIGHT_02","bgm":"CUTSCENE_TRAGEDY_SOFT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MORDRED_ROOT_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MORS_SHADOW_CA_NULL","face":"UNIT_IDLE"}}}},{"id":"L46_1","type":"dialog","speaker":"MORDRED_ROOT_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"PRISON_NIGHT_02","bgm":"CUTSCENE_TRAGEDY_SOFT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MORDRED_ROOT_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MORS_SHADOW_CA_NULL","face":"UNIT_IDLE"}}}},{"id":"L47_1","type":"dialog","speaker":"MORDRED_ROOT_NULL_NULL","text":{"KOREA":"그렇다면 말씀해주세요, 추기경님.","JPN":"だとしたら、お答えください、枢機卿様。","ENG":"Then tell me, Her Eminence.","TWN":"那麼請主教告訴我。"},"stage":{"bg":"PRISON_NIGHT_02","bgm":"CUTSCENE_TRAGEDY_SOFT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MORDRED_ROOT_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MORS_SHADOW_CA_NULL","face":"UNIT_IDLE"}}}},{"id":"L48_1","type":"dialog","speaker":"MORDRED_ROOT_NULL_NULL","text":{"KOREA":"이 낙인이 제가 죽어 마땅한 사람이란 뜻이라면… 전 두말없이 받아들이겠어요.","JPN":"この烙印は、私が死ぬにふさわしいものだとおっしゃるのでしたら……私は恐れずに死を受け入れます。","ENG":"If you say that I deserve to die because I have this mark... I will accept my fate.","TWN":"如果這個烙印表示我該死…我會毫不猶豫地接受。"},"stage":{"bg":"PRISON_NIGHT_02","bgm":"CUTSCENE_TRAGEDY_SOFT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MORDRED_ROOT_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MORS_SHADOW_CA_NULL","face":"UNIT_IDLE"}}}},{"id":"L49_1","type":"dialog","speaker":"MORS_SHADOW_CA_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"PRISON_NIGHT_02","bgm":"CUTSCENE_TRAGEDY_SOFT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MORDRED_ROOT_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MORS_SHADOW_CA_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L2_1","type":"dialog","speaker":"MORDRED_ROOT_NULL_NULL","text":{"KOREA":"추기경님…? 어째서 문을…?","JPN":"枢機卿様……？　どうして扉を……？","ENG":"Her Eminence...? Why are you opening the door...?","TWN":"主教…？為什麼要把門打開…？"},"stage":{"bg":"PRISON_NIGHT_02","bgm":"CUTSCENE_TRAGEDY_SOFT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORDRED_ROOT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"MORS_SHADOW_CA_NULL","text":{"KOREA":"떠나라.","JPN":"立ち去れ。","ENG":"Leave.","TWN":"離開吧。"},"stage":{"bg":"PRISON_NIGHT_02","bgm":"CUTSCENE_TRAGEDY_SOFT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_CA_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"MORS_SHADOW_CA_NULL","text":{"KOREA":"고작 낙인 때문에 너를 잃을 수는 없다.","JPN":"たかがその烙印故に、そなたを失うわけにはいかぬ。","ENG":"I cannot lose you all because of a trivial mark.","TWN":"我不能因為一個烙印而失去你。"},"stage":{"bg":"PRISON_NIGHT_02","bgm":"CUTSCENE_TRAGEDY_SOFT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_CA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"MORDRED_ROOT_NULL_NULL","text":{"KOREA":"이렇게 살아남는다고 해도… 제가 뭘 해야 하죠?","JPN":"仮に生き残れたとしても……私は何をすればよろしいでしょうか？","ENG":"But even if I keep living... what am I supposed to do?","TWN":"就算這樣活下來…我該做什麼呢？"},"stage":{"bg":"PRISON_NIGHT_02","bgm":"CUTSCENE_TRAGEDY_SOFT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORDRED_ROOT_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"MORDRED_ROOT_NULL_NULL","text":{"KOREA":"이전엔 그 역할을 잘 알고 있다고 생각했는데… 이젠 모르겠어요.","JPN":"今までは自分のやるべきことが明確にわかっていたつもりでしたけど……もうわからなくなってしまいました。","ENG":"I thought I had a purpose before... but I don't know anymore.","TWN":"以前我以為很清楚自己的角色…但現在我不知道了。"},"stage":{"bg":"PRISON_NIGHT_02","bgm":"CUTSCENE_TRAGEDY_SOFT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORDRED_ROOT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"MORDRED_ROOT_NULL_NULL","text":{"KOREA":"그저… 끝나지 않는 어둠에 갇힌 기분이에요.","JPN":"ただ……果てしない暗闇の中に閉じ込められた気分です。","ENG":"I feel like... I'm trapped in endless darkness.","TWN":"就像是…被困在無盡的黑暗中。"},"stage":{"bg":"PRISON_NIGHT_02","bgm":"CUTSCENE_TRAGEDY_SOFT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORDRED_ROOT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"MORS_SHADOW_CA_NULL","text":{"KOREA":"여명은 기나긴 밤 끝에 떠오르는 법이니.","JPN":"黎明は長い夜の終わりに上るものだ。","ENG":"The night is darkest just before sunrise.","TWN":"黎明總是在漫長的黑夜之後升起。"},"stage":{"bg":"PRISON_NIGHT_02","bgm":"CUTSCENE_TRAGEDY_SOFT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_CA_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"MORS_SHADOW_CA_NULL","text":{"KOREA":"좌절하지 말고, 때를 기다리거라.","JPN":"それまでは辛抱し、ときを待て。","ENG":"Do not be discouraged and wait for your time.","TWN":"不要氣餒，去等待時機吧。"},"stage":{"bg":"PRISON_NIGHT_02","bgm":"CUTSCENE_TRAGEDY_SOFT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_CA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"MORS_SHADOW_CA_NULL","text":{"KOREA":"비록 지금은 우리가 함께 할 수 없지만…","JPN":"今は一時的に離れ離れになるが……","ENG":"Although we will not be together right now...","TWN":"雖然現在我無法陪伴在你身邊…"},"stage":{"bg":"PRISON_NIGHT_02","bgm":"CUTSCENE_TRAGEDY_SOFT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_CA_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"MORS_SHADOW_CA_NULL","text":{"KOREA":"나와 순례단이 마왕을 처단하는 그날, 내가 너를 먼저 찾아가마.","JPN":"我と巡礼団が魔王を倒したら、すぐにそなたに会いに行こう。","ENG":"on the day that the pilgrimage and I slay the Demon Lord, I will come to you.","TWN":"在我和朝聖團消滅魔王的那天，我會來去你。"},"stage":{"bg":"PRISON_NIGHT_02","bgm":"CUTSCENE_TRAGEDY_SOFT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_CA_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"MORS_SHADOW_CA_NULL","text":{"KOREA":"그러니…","JPN":"だから……","ENG":"So...","TWN":"所以…"},"stage":{"bg":"PRISON_NIGHT_02","bgm":"CUTSCENE_TRAGEDY_SOFT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORDRED_ROOT_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"MORS_SHADOW_CA_NULL","text":{"KOREA":"살아남아다오.","JPN":"生き延びていてくれ。","ENG":"Live.","TWN":"你要活下去。"},"stage":{"bg":"SKY_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L20_1","type":"narration","speaker":null,"text":{"KOREA":"우리가 잠들어 있을 때에도, 세계는 종말을 향해 다가가고 있다.","JPN":"私たちの眠っている間にも、世界は終末に向かいつつある。","ENG":"Even when we are in slumber, the end of the world is nigh.","TWN":"就算我們在沉睡時，世界也在走向末日。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L21_1","type":"narration","speaker":null,"text":{"KOREA":"많은 사람들이 두려워하는 이야기였다.","JPN":"多くの人々が恐れる予言であった。","ENG":"It was a story many people feared.","TWN":"這是一個讓許多人都害怕的事實。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L22_1","type":"narration","speaker":null,"text":{"KOREA":"그런 현실을 외면하기 보단, 어둠 속 세상을 밝히는 빛이 되고 싶었다.","JPN":"その現実から目をそらすのではなく、暗闇の中からこの世を照らす光になりたかった。","ENG":"Instead of ignoring reality, I wanted to become the light that brightens the world from darkness.","TWN":"與其逃避這樣的事實，我更想成為黑暗中那束照亮世界的光。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L23_1","type":"narration","speaker":null,"text":{"KOREA":"하지만 내가 가진 낙인의 의미를 알았을 때…","JPN":"でも、自分の身体にある烙印の意味を知ってからは……","ENG":"But when I found out what the mark I had meant...","TWN":"但當我明白我身上那個烙印的意義之時…"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L24_1","type":"narration","speaker":null,"text":{"KOREA":"사람들이 두려워하는 어둠은 내가 되어있었다.","JPN":"人々が恐れる暗闇は、私自身となってしまっていた。","ENG":"I became the darkness that everyone feared.","TWN":"我變成了人們所畏懼的黑暗。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L26_1","type":"dialog","speaker":"MORDRED_ROOT_NULL_LU","text":{"KOREA":"휴우.","JPN":"ふう。","ENG":"Phew.","TWN":"呼。"},"stage":{"bg":"NOMAD_BORDER","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORDRED_ROOT_NULL_LU","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"MORDRED_ROOT_NULL_LU","text":{"KOREA":"어렵게 피운만큼, 참 아늑한 불이네요.","JPN":"苦労して起こしただけあって、本当に温かく感じます。","ENG":"Although it was difficult to light, it's such a cozy fire.","TWN":"好不容易升起來的火焰，真是非常溫暖呢。"},"stage":{"bg":"NOMAD_BORDER","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORDRED_ROOT_NULL_LU","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"MORDRED_ROOT_NULL_LU","text":{"KOREA":"운 좋게, 아직 썩지 않은 토끼도 구했어요.","JPN":"幸運なことに、腐る前のうさぎも見つけました。","ENG":"Luckily, I even found a rabbit that hadn't rotted yet.","TWN":"運氣真好，找到一隻還沒有腐爛的兔子。"},"stage":{"bg":"NOMAD_BORDER","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORDRED_ROOT_NULL_LU","face":"UNIT_IDLE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"MORDRED_ROOT_NULL_LU","text":{"KOREA":"나무껍질 대신 영양가 있는 고기를 먹을 수 있다는 건 참 좋네요.","JPN":"木の皮じゃなくて、きちんと栄養のある肉が食べられるのは、すごく幸せです。","ENG":"It's great to be able to eat nutritious meat instead of tree bark.","TWN":"能吃到有營養的肉而不是樹皮，真是太好了。"},"stage":{"bg":"NOMAD_BORDER","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORDRED_ROOT_NULL_LU","face":"UNIT_PRIDE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"MORDRED_ROOT_NULL_LU","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"NOMAD_BORDER","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORDRED_ROOT_NULL_LU","face":"UNIT_IDLE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"MORDRED_ROOT_NULL_LU","text":{"KOREA":"힘내서 다시 요정을 찾아보는 거예요.","JPN":"また頑張って妖精を探しに行きましょう。","ENG":"Now, I should pick myself up and go look for the fairy again.","TWN":"加油，再去找找精靈吧。"},"stage":{"bg":"NOMAD_BORDER","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORDRED_ROOT_NULL_LU","face":"UNIT_IDLE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"MORDRED_ROOT_NULL_LU","text":{"KOREA":"소원을 빌어 이 저주받은 낙인을 지우면…","JPN":"願いを叶えてもらい、この呪われた烙印を消すことができれば……","ENG":"If I can make my wish and remove this cursed mark...","TWN":"許下願望，消除這個被詛咒的烙印…"},"stage":{"bg":"SKY","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L35_1","type":"dialog","speaker":"MORDRED_ROOT_NULL_LU","text":{"KOREA":"엘리시온으로 돌아갈 수 있을 테니까.","JPN":"エリシオンに戻ることだってできるはずだから。","ENG":"I'll be able to return to Elysion.","TWN":"就能回到艾利森了。"},"stage":{"bg":"SKY","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}}]`);export{e as default};